import{_ as t,o,c as a,aq as r}from"./chunks/framework.DH0nG2Fl.js";const u=JSON.parse('{"title":"Extension Development","description":"","frontmatter":{"prev":{"text":"Development Guides","link":"/development/"},"next":{"text":"Your first Extension","link":"/development/extensions/start"}},"headers":[],"relativePath":"development/extensions/index.md","filePath":"development/extensions/index.md","lastUpdated":1782431519000}'),i={name:"development/extensions/index.md"};function n(s,e,l,p,h,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="extension-development" tabindex="-1">Extension Development <a class="header-anchor" href="#extension-development" aria-label="Permalink to “Extension Development”">​</a></h1><p>If you&#39;re reading this, it probably means you want to learn how to make an extension for Paperback. Awesome! You&#39;ve come to the right place. This guide will teach you things such as:</p><ul><li>Making the base of an extension from scratch.</li><li>Understanding what does an extension needs to do and what it can do.</li><li>Using the right tool, and how to debug.</li><li>How to organize the code of your extension.</li><li>A detailed look on advanced features.</li><li>And much more...</li></ul><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to “Before you begin”">​</a></h2><h3 id="about-paperback-0-9" tabindex="-1">About Paperback 0.9 <a class="header-anchor" href="#about-paperback-0-9" aria-label="Permalink to “About Paperback 0.9”">​</a></h3><p>Together, we will be making step by step an extension for Paperback, but we will be making one for Paperback version 0.9. I understand that 0.9 isn&#39;t available for everyone (for now) but I will share a secret with you if you make a modmail on the <a href="https://discord.com/invite/paperback" target="_blank" rel="noreferrer">official paperback server</a> saying that you are a developer, sharing you GitHub account or other proof, they might grant you the role : <code>TestFlight Bypass</code> then you can access the Beta release of Paperback 0.9. But if you don&#39;t code please don&#39;t bother asking them. But if you already code a bit and think &quot;Oh, I don&#39;t want to bother them...&quot; please think again, they are glad to help you, Paperback wouldn&#39;t exist if people all around the world didn&#39;t contribute to this project, this is a great learning opportunity.</p><h3 id="programming-language-prerequisite" tabindex="-1">Programming language prerequisite <a class="header-anchor" href="#programming-language-prerequisite" aria-label="Permalink to “Programming language prerequisite”">​</a></h3><p>Also, we will be coding in TypeScript, using Npm as a packet manager. If you don&#39;t know how to code in TypeScript or you have only coded in JavaScript please follow those resources</p><ul><li><a href="https://www.typescriptlang.org/docs/handbook/intro.html" target="_blank" rel="noreferrer">The TypeScript Handbook</a></li><li><a href="https://javascript.info/" target="_blank" rel="noreferrer">JavaScript.info</a>, if you don&#39;t know where to start because you know nothing about programming in JS, it&#39;s the place to be. Also, if you are not comfortable with async/await or Promises, review JavaScript fundamentals first.</li></ul><h3 id="web-interaction-prerequisite" tabindex="-1">Web interaction prerequisite <a class="header-anchor" href="#web-interaction-prerequisite" aria-label="Permalink to “Web interaction prerequisite”">​</a></h3><p>We will also be getting some information from websites using either REST API or some scrapping (using Cheerio). Keep in mind that Paperback use some custom functions so that we don&#39;t have to deal with CloudFlare protections by ourselves, so you need to learn the key consepts but the execution will be detailed in specific guides</p><ul><li><a href="https://www.restapitutorial.com/" target="_blank" rel="noreferrer">RestAPITutorial.com</a></li><li><a href="https://cheerio.js.org/docs/intro/" target="_blank" rel="noreferrer">Cheerio.js.org</a></li></ul><p>To be clear once again, this guide will not show you how to &quot;reverse engineer&quot; a website. If you don&#39;t know how to do it you can find a lot of resources at <a href="https://pptr.dev/guides/what-is-puppeteer" target="_blank" rel="noreferrer">pptr.dev</a> we will not be covering this here, you need to know witch endpoint returns what etc...</p>',13)])])}const b=t(i,[["render",n]]);export{u as __pageData,b as default};
